local function submitKey(key)
    key = M.cleanKey(key)
    if key == "" then
        Library:Notify({Title="⚠️ Walang Key na Nailagay", Description="Pakilagay ang iyong key.", Time=3})
        return
    end
    if VaultModule and VaultModule.validateKey then
        local ok = VaultModule.validateKey(key, M.hwid, Library)
        if ok then
            Library:Notify({Title="🔓 Nilo-load", Description="Nilo-load ang premium script...", Time=2})
            if VaultModule.startSessionMonitoring then pcall(VaultModule.startSessionMonitoring, M.hwid) end
            if getgenv then pcall(function() getgenv().VaultReady = true end) end
            if M.safeToLoad() and execPremiumScript then pcall(execPremiumScript) end
            task.wait(2)
            pcall(function() Library:Unload() end)
        else
            Library:Notify({Title="❌ Invalid na Key", Description="Hindi valid ang key na iyan. Pakisuri ito at subukang muli.", Time=4})
        end
    else
        local kr = M.withRetry(M.checkKey, M.encryptedHWID)
        if kr and kr.success == true then
            local url = M.getChronicleScript(game.PlaceId)
            if url and M.runUrl(url) then task.wait(1); pcall(function() Library:Unload() end); return end
        end
        Library:Notify({Title="Key Check", Description="Walang aktibong key na nahanap. I-activate ang iyong key sa website, tapos patakbuhin muli ang script.", Time=6})
    end
end

local function readKeyFromBox()
    local raw
    pcall(function()
        local holder = Options and Options.KeyInput and Options.KeyInput.Holder
        local box = holder and holder:FindFirstChildOfClass("TextBox")
        if box then raw = box.Text end
    end)
    local key = M.cleanKey(raw)
    if key == "" then key = M.cleanKey(Options and Options.KeyInput and Options.KeyInput.Value) end
    if key == "" then key = M.cleanKey(keyInputValue) end
    return key
end

