local FEEDBACK_COOLDOWN, lastFeedback = 20, 0
local ERRMAP = {
    empty = "Walang laman ang mensahe.", no_links = "Hindi pinapayagan ang mga link.",
    too_long = "Masyadong mahaba ang mensahe (500 karakter maximum).", rate_limited = "Naabot mo na ang limitasyong 3 mensahe. Pakisubukang muli mamaya.",
    busy = "Busy ang server. Pakisubukang muli.", banned = "Hindi ka pinapayagang magpadala ng feedback.",
    discord_error = "Nabigo ang pagpapadala. Pakisubukang muli.", network = "May error sa network.",
    no_request = "Hindi makapagpadala ng requests ang iyong executor.", bad_response = "Nagbalik ang server ng hindi inaasahang response.",
    unreachable = "Hindi maabot ng iyong executor ang server (TLS error). Sumubok ng ibang executor.",
}
local FG = Tabs.Suggest:AddLeftGroupbox("Mga Suhestiyon / Tulong", "message-square")
FG:AddDropdown("FeedbackType", {Text = "Uri", Values = {"Suggestion", "Bug", "Help"}, Default = "Suggestion", Callback = function() end})
FG:AddInput("FeedbackMsg", {Default = "", Numeric = false, Finished = false, ClearTextOnFocus = false, Text = "Mensahe", Placeholder = "I-type ang iyong mensahe (500 karakter maximum, walang link)"})
local fbStatus = FG:AddLabel("", true)
FG:AddButton({
    Text = "📨 Send",
    Func = function()
        local now = tick()
        if now - lastFeedback < FEEDBACK_COOLDOWN then
            safeSet(fbStatus, string.format("Maghintay ng %d segundo bago magpadala muli.", math.ceil(FEEDBACK_COOLDOWN - (now - lastFeedback))))
            return
        end
        local ftype = tostring((Options.FeedbackType and Options.FeedbackType.Value) or "Suggestion"):lower()
        local msg   = M.trim((Options.FeedbackMsg and Options.FeedbackMsg.Value) or "")
        if msg == "" then safeSet(fbStatus, "Walang laman ang mensahe."); return end
        if #msg > 500 then safeSet(fbStatus, "Masyadong mahaba ang mensahe (500 karakter maximum)."); return end
        local low = msg:lower()
        if low:find("http", 1, true) or low:find("discord.gg", 1, true) or low:find("www.", 1, true) or low:find(".gg/", 1, true) then
            safeSet(fbStatus, "Hindi pinapayagan ang mga link."); return
        end
        safeSet(fbStatus, "Nagpapadala...")
        task.spawn(function()
            local sok, err = M.sendFeedback(ftype, msg, (preCheck and preCheck.session_token) or "")
            if sok then
                lastFeedback = tick()
                safeSet(fbStatus, "✅ Naipadala. Salamat!")
                pcall(function() Options.FeedbackMsg:SetValue("") end)
                Library:Notify({Title = "COMBOWICK", Description = "Naipadala ang iyong feedback. Salamat!", Time = 3})
            else
                safeSet(fbStatus, ERRMAP[err] or ("Nabigong ipadala: " .. tostring(err)))
            end
        end)
    end,
})
FG:AddLabel("Maximum 3 mensahe kada oras. Walang link o mentions.", true)

