task.spawn(function()
    safeSet(statusLabel, "Nag-a-authenticate...")

    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "Status: Nabigo")
        Library:Notify({Title="COMBOWICK", Description="Nabigo ang session check.", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ Naka-disable ang Laro")
            safeSet(hintLabel, "Hindi available ang libreng bersyon dito. Kumuha ng key.")
            Library:Notify({Title="COMBOWICK", Description="Naka-disable ang libreng bersyon para sa laro na ito. Gumamit ng key.", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "Status: Nabigo")
        else
            safeSet(statusLabel, "Status: Authenticated")
            Library:Notify({Title="COMBOWICK", Description="Ikaw ay authenticated na.", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("Natitirang oras: %s", fmt))
                    safeSet(lSession, string.format("Oras ng session: %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "Nag-expire na ang session.")
                safeSet(lSession, "Oras ng session: nag-expire")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Naka-cooldown")
        safeSet(hintLabel, "Kumuha ng 11-oras na key, o maghintay hanggang matapos ang cooldown.")
        Library:Notify({Title="COMBOWICK", Description="Ikaw ay naka-cooldown. Kumuha ng key para laktawan ang paghihintay.", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("Cooldown: %s", fmt))
                safeSet(lCooldown, string.format("Cooldown: %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Tapos na ang cooldown.")
            safeSet(lCooldown, "Cooldown: tapos na")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="Tapos na ang cooldown. Nirerload...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Masyadong Maraming Requests")
        safeSet(hintLabel, "Masyadong maraming requests. Pakihintay.")
        Library:Notify({Title="COMBOWICK", Description="Masyadong maraming requests. Sandaling maghintay.", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("Subukang muli sa %s", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Nirerload...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "Naka-pause ang Serbisyo")
        safeSet(hintLabel, "Pansamantalang offline ang COMBOWICK.")
        Library:Notify({Title="COMBOWICK", Description="Kasalukuyang naka-disable ang serbisyo. Pakisubukang muli mamaya.", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "Na-ban")
        Library:Notify({Title="COMBOWICK", Description="Ikaw ay na-ban.", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 Hindi Suportado ang Laro")
        safeSet(hintLabel, "Hindi pa suportado ang laro na ito. Gumagana pa rin ang premium keys kung may available na script.")
        Library:Notify({Title="COMBOWICK", Description="Hindi pa suportado ang laro na ito.", Time=6})

    else
        safeSet(statusLabel, "Error")
        safeSet(hintLabel, "Hindi maabot ang server. Pakipatakbo muli ang script.")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "May naganap na hindi kilalang error."), Time=5})
    end
end)

